#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main()
{
    vector<int> numbers = {10, 25, 3, 47, 8};

    cout << "Vector uzunlugu: " << numbers.size() << endl;

    sort(numbers.begin(), numbers.end());

    cout << "Siralanmis vector: ";
    for (int n : numbers)
    {
        cout << n << " ";
    }
    cout << endl;

    // Eleman ekleme
    numbers.push_back(100);
    cout << "\n100 eklendi, yeni boyut: " << numbers.size() << endl;

    // Eleman silme
    numbers.erase(numbers.begin());
    cout << "Ilk eleman silindi, yeni boyut: " << numbers.size() << endl;

    // Toplam hesaplama
    int total = 0;
    for (int n : numbers)
    {
        total += n;
    }
    cout << "\nToplam: " << total << endl;

    // find ile arama
    auto it = find(numbers.begin(), numbers.end(), 47);
    if (it != numbers.end())
    {
        cout << "\n47 vektorde bulundu." << endl;
    }

    return 0;
}
